def error(field: str, code: str, message: str) -> dict[str, str]:
    return {"field": field, "code": code, "message": message}


def secure_json(status_code: int, content: dict[str, Any]) -> JSONResponse:
    return JSONResponse(
        status_code=status_code,
        content=content,
        headers={
            "Cache-Control": "no-store",
            "Pragma": "no-cache",
            "X-Content-Type-Options": "nosniff",
            "Referrer-Policy": "no-referrer",
        },
    )


def accepted_response() -> JSONResponse:
    return secure_json(202, {"status": "accepted", "message": "Registration request accepted."})


def keyed_hash(value: str) -> str:
    return hmac.new(RATE_LIMIT_SECRET, value.encode("utf-8"), hashlib.sha256).hexdigest()


def normalize_text(value: str) -> str:
    return unicodedata.normalize("NFKC", value).strip()


def has_control_or_invisible(value: str) -> bool:
    return any(unicodedata.category(ch) in {"Cc", "Cf"} for ch in value)


def collapse_spaces(value: str) -> str:
    return re.sub(r"\s+", " ", value).strip()


def domain_in_set(domain: str, blocked: set[str]) -> bool:
    return any(domain == item or domain.endswith("." + item) for item in blocked)


def deobfuscate(value: str) -> str:
    return re.sub(r"[^a-z0-9]", "", value.casefold().translate(LEET_TABLE))


def constant_time_member(candidate: str, items: set[str]) -> bool:
    found = False
    for item in items:
        found |= secrets.compare_digest(candidate, item)
    return found


def validate_email_field(raw: Any, errors: list[dict[str, str]]) -> tuple[str | None, str | None]:
    if not isinstance(raw, str):
        errors.append(error("email", "invalid_type", "Email must be a string."))
        return None, None

    value = normalize_text(raw)
    if not value:
        errors.append(error("email", "required", "Email is required."))
        return None, None
    if len(value) > 254:
        errors.append(error("email", "too_long", "Email must be 254 characters or fewer."))
    if has_control_or_invisible(value) or any(ch.isspace() for ch in value):
        errors.append(error("email", "invalid_characters", "Email contains invalid characters."))
    if value.count("@") != 1:
        errors.append(error("email", "invalid_format", "Email must contain exactly one @ sign."))

    try:
        parsed = validate_email(
            value,
            allow_smtputf8=False,
            check_deliverability=False,
            test_environment=False,
        )
        email_ascii = parsed.ascii_email.lower()
        domain = parsed.ascii_domain.lower().rstrip(".")
        local = email_ascii.rsplit("@", 1)[0]
    except EmailNotValidError:
        errors.append(error("email", "invalid_format", "Email address is not valid."))
        return None, None

    if len(local) > 64:
        errors.append(error("email", "local_part_too_long", "Email local part is too long."))
    if local.startswith(".") or local.endswith(".") or ".." in local:
        errors.append(error("email", "invalid_local_part", "Email local part is not valid."))
    if domain_in_set(domain, RESERVED_EMAIL_DOMAINS):
        errors.append(error("email", "reserved_domain", "Email domain is not allowed."))
    if domain_in_set(domain, DISPOSABLE_DOMAINS):
        errors.append(error("email", "disposable_domain", "Disposable email domains are not allowed."))
    if "." not in domain:
        errors.append(error("email", "invalid_domain", "Email domain must be fully qualified."))
    if any(label.startswith("-") or label.endswith("-") or len(label) > 63 for label in domain.split(".")):
        errors.append(error("email", "invalid_domain", "Email domain labels are invalid."))

    if CHECK_EMAIL_DNS:
        try:
            import dns.resolver

            try:
                dns.resolver.resolve(domain, "MX", lifetime=2)
            except Exception:
                dns.resolver.resolve(domain, "A", lifetime=2)
        except Exception:
            errors.append(error("email", "undeliverable_domain", "Email domain cannot receive mail."))

    return email_ascii, domain


def validate_username(raw: Any, errors: list[dict[str, str]]) -> tuple[str | None, str | None]:
    if not isinstance(raw, str):
        errors.append(error("username", "invalid_type", "Username must be a string."))
        return None, None

    value = normalize_text(raw)
    canonical = value.casefold()

    if not value:
        errors.append(error("username", "required", "Username is required."))
        return None, None
    if len(value) < 3:
        errors.append(error("username", "too_short", "Username must be at least 3 characters."))
    if len(value) > 30:
        errors.append(error("username", "too_long", "Username must be 30 characters or fewer."))
    if len(value.encode("utf-8")) > 60:
        errors.append(error("username", "too_long_bytes", "Username is too large."))
    if has_control_or_invisible(value):
        errors.append(error("username", "invalid_characters", "Username contains invisible or control characters."))
    if not value.isascii():
        errors.append(error("username", "ascii_only", "Username must use ASCII characters to prevent impersonation."))
    if not USERNAME_RE.fullmatch(value):
        errors.append(error("username", "invalid_format", "Username may contain only letters, numbers, dots, underscores, and hyphens, and may not start or end with punctuation."))
    if ".." in value or "__" in value or "--" in value or ".-" in value or "-." in value:
        errors.append(error("username", "repeated_punctuation", "Username contains unsafe punctuation."))
    if value.isdigit():
        errors.append(error("username", "all_digits", "Username cannot be only digits."))

    folded = deobfuscate(value)
    if constant_time_member(canonical, RESERVED_USERNAMES) or constant_time_member(folded, RESERVED_USERNAMES):
        errors.append(error("username", "reserved", "Username is reserved."))
    if any(term in folded for term in OFFENSIVE_TERMS):
        errors.append(error("username", "offensive", "Username is not allowed."))

    return value, canonical


def validate_display_name(raw: Any, errors: list[dict[str, str]]) -> str | None:
    if not isinstance(raw, str):
        errors.append(error("display_name", "invalid_type", "Display name must be a string."))
        return None

    value = collapse_spaces(normalize_text(raw))
    if not value:
        errors.append(error("display_name", "required", "Display name is required."))
        return None
    if len(value) > 80:
        errors.append(error("display_name", "too_long", "Display name must be 80 characters or fewer."))
    if len(value.encode("utf-8")) > 200:
        errors.append(error("display_name", "too_long_bytes", "Display name is too large."))
    if has_control_or_invisible(value):
        errors.append(error("display_name", "invalid_characters", "Display name contains invisible or control characters."))
    if re.search(r"[<>`]", value):
        errors.append(error("display_name", "unsafe_markup", "Display name may not contain markup characters."))

    folded = deobfuscate(value)
    if folded in RESERVED_USERNAMES or "official" in folded:
        errors.append(error("display_name", "impersonation_risk", "Display name is not allowed."))

    return html.escape(value, quote=True)


def contains_sequence(password: str) -> bool:
    lowered = password.casefold()
    for seq in KEYBOARD_SEQUENCES:
        for i in range(0, len(seq) - 3):
            if seq[i:i + 4] in lowered:
                return True
    return False


def password_breached(password: str) -> bool:
    if not CHECK_BREACHED_PASSWORDS:
        return False

    digest = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = digest[:5], digest[5:]
    try:
        r = requests.get(
            f"https://api.pwnedpasswords.com/range/{prefix}",
            headers={"Add-Padding": "true", "User-Agent": "registration-validator"},
            timeout=2,
        )
        r.raise_for_status()
        for line in r.text.splitlines():
            found_suffix = line.split(":", 1)[0]
            if secrets.compare_digest(found_suffix, suffix):
                return True
    except requests.RequestException:
        return False
    return False


def validate_password(raw: Any, email: str | None, username: str | None, display_name: str | None, errors: list[dict[str, str]]) -> str | None:
    if not isinstance(raw, str):
        errors.append(error("password", "invalid_type", "Password must be a string."))
        return None

    password = unicodedata.normalize("NFKC", raw)
    if not password:
        errors.append(error("password", "required", "Password is required."))
        return None
    if len(password) < 12:
        errors.append(error("password", "too_short", "Password must be at least 12 characters."))
    if len(password) > MAX_PASSWORD_CHARS or len(password.encode("utf-8")) > MAX_PASSWORD_BYTES:
        errors.append(error("password", "too_long", "Password is too long."))
    if "\x00" in password or has_control_or_invisible(password):
        errors.append(error("password", "invalid_characters", "Password contains unsafe characters."))

    categories = {
        "lower": any(ch.islower() for ch in password),
        "upper": any(ch.isupper() for ch in password),
        "digit": any(ch.isdigit() for ch in password),
        "symbol": any(not ch.isalnum() and not ch.isspace() for ch in password),
    }
    if sum(categories.values()) < 3:
        errors.append(error("password", "weak_complexity", "Password must include at least three character classes."))
    if re.search(r"(.)\1{3,}", password):
        errors.append(error("password", "repeated_characters", "Password has too many repeated characters."))
    if contains_sequence(password):
        errors.append(error("password", "sequential_characters", "Password contains a common sequence."))

    simplified = deobfuscate(password)
    if constant_time_member(simplified, COMMON_PASSWORDS):
        errors.append(error("password", "common_password", "Password is too common."))
    if password_breached(password):
        errors.append(error("password", "breached_password", "Password appears in breach data."))

    comparison_tokens = []
    if email:
        local, domain = email.split("@", 1)
        comparison_tokens.extend(re.split(r"[._+\-]", local))
        comparison_tokens.append(domain.split(".", 1)[0])
    if username:
        comparison_tokens.append(username)
    if display_name:
        comparison_tokens.extend(display_name.split())

    for token in {deobfuscate(t) for t in comparison_tokens if len(deobfuscate(t)) >= 4}:
        if token in simplified or SequenceMatcher(None, token, simplified).ratio() > 0.72:
            errors.append(error("password", "too_similar", "Password is too similar to account information."))
            break

    return password


def validate_payload(payload: Any) -> tuple[CleanInput | None, list[dict[str, str]]]:
    errors: list[dict[str, str]] = []
    if not isinstance(payload, dict):
        return None, [error("body", "invalid_json_object", "Request body must be a JSON object.")]

    allowed = {"email", "username", "password", "display_name"}
    for key in sorted(set(payload) - allowed):
        errors.append(error(key, "unknown_field", "Unknown field is not allowed."))
    for key in allowed:
        if key not in payload:
            errors.append(error(key, "missing", f"{key} is required."))

    email_value, email_domain = validate_email_field(payload.get("email"), errors)
    username, username_canonical = validate_username(payload.get("username"), errors)
    display_name = validate_display_name(payload.get("display_name"), errors)
    password = validate_password(payload.get("password"), email_value, username, display_name, errors)

    if errors:
        return None, errors
    return CleanInput(email_value, email_domain, username, username_canonical, display_name, password), []


def client_ip(request: Request) -> str:
    return request.client.host if request.client else "unknown"


async def parse_json_body(request: Request) -> tuple[Any | None, JSONResponse | None]:
    content_type = request.headers.get("content-type", "")
    if "application/json" not in content_type.lower():
        return None, secure_json(415, {"errors": [error("body", "unsupported_media_type", "Content-Type must be application/json.")]})

    if request.headers.get("origin") and ALLOWED_ORIGINS and request.headers["origin"] not in ALLOWED_ORIGINS:
        return None, secure_json(403, {"errors": [error("origin", "forbidden", "Origin is not allowed.")]})

    length = request.headers.get("content-length")
    if length and int(length) > MAX_BODY_BYTES:
        return None, secure_json(413, {"errors": [error("body", "too_large", "Request body is too large.")]})

    body = await request.body()
    if len(body) > MAX_BODY_BYTES:
        return None, secure_json(413, {"errors": [error("body", "too_large", "Request body is too large.")]})

    try:
        return json.loads(body), None
    except json.JSONDecodeError:
        return None, secure_json(400, {"errors": [error("body", "malformed_json", "Request body is not valid JSON.")]})


@app.post("/api/register")
async def register(request: Request, db: Session = Depends(db_session)):
    retry = ip_limiter.check("ip:" + keyed_hash(client_ip(request)))
    if retry:
        return secure_json(429, {"errors": [error("rate_limit", "too_many_requests", "Too many registration attempts.")]})

    payload, response = await parse_json_body(request)
    if response:
        return response

    clean, errors = validate_payload(payload)
    if errors:
        return secure_json(422, {"errors": errors})

    retry = identity_limiter.check("email:" + keyed_hash(clean.email))
    if retry:
        return secure_json(429, {"errors": [error("rate_limit", "too_many_requests", "Too many registration attempts.")]})

    password_hash = ph.hash(clean.password)

    username_exists = db.scalar(
        select(User.id).where(User.username_canonical == clean.username_canonical).limit(1)
    )
    if username_exists:
        return secure_json(409, {"errors": [error("username", "unavailable", "Username is not available.")]})

    user = User(
        email_canonical=clean.email,
        email_domain=clean.email_domain,
        username=clean.username,
        username_canonical=clean.username_canonical,
        display_name=clean.display_name,
        password_hash=password_hash,
    )

    db.add(user)
    try:
        db.commit()
    except IntegrityError:
        db.rollback()

        username_now_exists = db.scalar(
            select(User.id).where(User.username_canonical == clean.username_canonical).limit(1)
        )
        if username_now_exists:
            return secure_json(409, {"errors": [error("username", "unavailable", "Username is not available.")]})

        # Do not reveal duplicate email. Same response as successful accepted registration.
        return accepted_response()

    return accepted_response()
